(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).ru = [
  { id:1, topic:"Безопасная вода", emoji:"💧",
    question:"Какая вода безопасна и не вызовет боль в животе?",
    choices:["Речная вода","Колодезная вода","Вода, хорошо прокипячённая на огне","Дождевая вода"],
    answerIndex:2,
    explanation:"Речная, колодезная и дождевая вода может выглядеть совершенно прозрачной и чистой, но в ней может быть полно крошечных живых существ, которых не видят наши глаза (микробы и вирусы). Если выпить такую воду как есть, это может вызвать сильную боль в животе или опасную для жизни болезнь. Но когда ты ставишь воду на огонь и сильно кипятишь её, пока не пойдут пузырьки, жар убивает всех этих вредных существ. Поэтому вода, которую хорошо прокипятили и затем остудили, — самая безопасная в мире, и её можно пить спокойно." },
  { id:2, topic:"Мытьё рук", emoji:"🧼",
    question:"Что нужно сделать перед едой?",
    choices:["Помыть руки водой с мылом","Вытереть руки об одежду","Ничего не делать","Потрогать землю"],
    answerIndex:0,
    explanation:"Наши руки каждый день трогают много предметов и землю, поэтому незаметно собирают множество невидимых микробов. Если трогать еду такими руками, микробы переходят на еду, и ты проглатываешь их в тело вместе с ней. Если вытереть руки о грязную одежду или просто смочить водой, микробы не уходят — они крепко держатся. Только используя мыло и хорошо натирая пеной ладони, тыльную сторону рук и между пальцами, а затем смывая водой, ты по-настоящему убираешь микробы." },
  { id:3, topic:"Мытьё рук", emoji:"🚽",
    question:"Что нужно сделать после туалета?",
    choices:["Сразу идти играть","Помыть руки водой с мылом","Вытереть руки об одежду","Вытереть руки о штаны"],
    answerIndex:1,
    explanation:"После туалета на руках легко остаются очень сильные микробы из кала и мочи, которые вызывают болезни. Если пойти играть, не помыв руки, эти микробы попадают на дверные ручки и игрушки, которых ты касаешься, и передают болезнь следующему другу или члену семьи, который их трогает. А если такими руками тронуть свой рот или глаза, можно заболеть и самому. Как бы ты ни спешил, всегда хорошо мыть руки водой с мылом после туалета — это правило, которое защищает твою жизнь и жизнь окружающих." },
  { id:4, topic:"Здоровье", emoji:"💧",
    question:"Когда живот расстроен и стул стал водянистым (понос), что важнее всего?",
    choices:["Много есть","Ничего не пить","Пить много безопасной воды","Бегать и играть"],
    answerIndex:2,
    explanation:"Когда живот расстроен и водянистый стул (понос) выходит снова и снова, тело без остановки теряет драгоценную воду и питательные вещества. Это называется обезвоживанием. Когда телу не хватает воды, важные функции, которые держат нас в живых, начинают останавливаться, и особенно маленькие дети могут внезапно потерять жизнь. При поносе вместо того, чтобы заставлять себя есть твёрдую пищу, лучше сначала восполнить потерянную воду. Если пить безопасную прокипячённую и остуженную воду понемногу и много раз, можно сохранить силы и защитить свою жизнь." },
  { id:5, topic:"Лечение ран", emoji:"🩹",
    question:"Когда ты упал и идёт кровь, что сделать сначала?",
    choices:["Насыпать земли","Хорошо промыть чистой водой","Оставить и ничего не делать","Тереть листом"],
    answerIndex:1,
    explanation:"Когда ты падаешь и получаешь кровоточащую рану, на ней земля, грязь и пыль с пола, а с ними много микробов. Если поверить старым приметам и насыпать земли, потереть грязным листом или оставить как есть, микробы уходят глубоко в рану и размножаются. Тогда рана краснеет, опухает и сильно болит, а в худшем случае рука или нога может загнить и перестать двигаться. Когда ты поранился, первый правильный шаг, чтобы рана не стала тяжёлой, — взять рядом чистую безопасную воду и сильной струёй смыть с раны грязь." },
  { id:6, topic:"Еда", emoji:"🦠",
    question:"Что происходит, когда еда портится (гниёт)?",
    choices:["Становится вкусной","Гниёт и вызывает боль в животе","Становится твёрдой","Ничего не меняется"],
    answerIndex:1,
    explanation:"В еде с самого начала есть небольшое число невидимых микробов. В прохладном месте микробы не могут быть активны, но если оставить еду надолго в тёплом, жарком месте, для них это идеальная среда, и за несколько часов они размножаются до миллионов — пугающего числа. Когда микробы размножаются так сильно и форма и свойства еды меняются, мы говорим, что она испортилась. В испорченной еде накапливается сильный яд, созданный микробами, поэтому, съев её, ты получишь сильную боль в животе, понос и тошноту и навредишь телу." },
  { id:7, topic:"Еда", emoji:"👃",
    question:"Какой признак того, что еда испортилась?",
    choices:["Странный запах или вкус","Красный цвет","Что-то холодное","Что-то хорошо приготовленное"],
    answerIndex:0,
    explanation:"Ты можешь использовать собственный нос и язык, чтобы проверить, испортилась ли еда и безопасна ли она ещё. Если у неё необычный кислый запах или резкий неприятный запах, или странный вкус, когда положишь немного в рот, или если она липкая и тянется нитями, это доказательство того, что микробы сильно размножились и образовался яд. Если заставить себя съесть её, потому что «жалко выбрасывать», ты подвергаешь жизнь опасности из-за сильного отравления. Если запах или вкус хоть немного подозрительны, реши выбросить её и никогда не глотай." },
  { id:8, topic:"Еда", emoji:"🪰",
    question:"Что делать с едой, на которую села муха?",
    choices:["Съесть как есть","Не есть место, которого коснулась муха (выбросить)","Растить муху","Просто смотреть"],
    answerIndex:1,
    explanation:"Насекомое, которое мы называем мухой, любит ходить по очень грязным, полным микробов местам — навозу животных, трупам и свалкам. Поэтому на её тонких лапках и теле плотно сидят микробы, вызывающие страшные болезни. Когда такая муха садится на нашу еду, в тот же миг микробы с её лапок переходят на еду. Если съесть место, которого она коснулась, ты косвенно отправляешь в рот микробы навоза и мусора, и это может вызвать тяжёлую болезнь. Хоть и кажется, что жалко, безопаснее срезать и выбросить ту часть еды, на которую села муха." },
  { id:9, topic:"Профилактика болезней", emoji:"🦟",
    question:"Что будет, если надолго оставить стоячую воду?",
    choices:["Вода станет чистой","Размножатся вредные комары","Станет больше денег","Ничего не случится"],
    answerIndex:1,
    explanation:"Старая вода, которая стоит в одном месте и не течёт, становится идеальным местом для насекомого по имени комар, чтобы откладывать яйца. Если оставить вокруг двора или дома вёдра, старые шины или пустые банки с водой, там рождаются сотни и тысячи новых комаров и летают повсюду. Когда комар сосёт кровь человека, он впрыскивает в тело микробы очень страшных и смертельных болезней, таких как малярия и лихорадка денге. Убирать лужи воды вокруг дома — важный план, чтобы защитить семью от этих страшных болезней." },
  { id:10, topic:"Чистота", emoji:"✋",
    question:"Когда ногти длинные, что в них скапливается?",
    choices:["Руки становятся сильнее","Под ногтями скапливается чёрная грязь и микробы","Еда становится вкуснее","Ничего не меняется"],
    answerIndex:1,
    explanation:"Когда ногти отрастают длинными, чёрная грязь плотно набивается в узкую щель между ногтем и кожей, когда ты играешь в земле, помогаешь или работаешь. Грязь, попавшая в эту щель, не уходит легко при обычном мытье рук и становится идеальным укрытием для микробов. С длинными ногтями, когда ты ешь руками или трогаешь своё лицо или рану, эти спрятанные микробы легко попадают в тело. Держать ногти всегда короткими — это базовый способ предотвратить болезни." },
  { id:11, topic:"Этикет при кашле", emoji:"🤧",
    question:"Что делать, когда кашляешь или чихаешь?",
    choices:["Делать это в лицо человеку","Прикрывать рот и нос рукой или рукавом","Громко кричать","Ничего не делать"],
    answerIndex:1,
    explanation:"Когда у тебя простуда или болезнь лёгких, всего один кашель или чих выбрасывает изо рта и носа невидимые крошечные капельки воды на несколько метров с большой силой. В каждой капельке могут быть десятки тысяч микробов болезни. Если кашлять в лицо человеку, ты передаёшь болезнь напрямую, а если ничем не прикрыть, микробы расходятся по воздуху, и все в той же комнате могут заболеть. Когда кашляешь, плотно прикрывая рот и нос рукавом или рукой, ты не передаёшь болезнь дорогим тебе родным и друзьям рядом." },
  { id:12, topic:"Чистота", emoji:"🗑️",
    question:"Что будет, если оставить мусор у дома?",
    choices:["Дом станет чистым","Соберутся вредные крысы и насекомые и распространится болезнь","Мусор превратится в цветы","Никаких проблем"],
    answerIndex:1,
    explanation:"Если выбрасывать остатки еды и мусор прямо у дома, запах привлекает много существ, таких как крысы, мухи и тараканы. Эти существа обычно ходят по канализации и грязным местам, поэтому несут на теле много микробов, вызывающих страшные болезни. Когда они размножаются вокруг мусора, в конце концов они проникают в дом и пачкают драгоценную еду и питьевую воду внутри. Мусор нужно выбрасывать в определённое место достаточно далеко от дома или закапывать глубоко в яму в земле." },
  { id:13, topic:"Здоровые зубы", emoji:"🪥",
    question:"Какая главная причина чистить зубы?",
    choices:["Покрасить зубы в белый","Уменьшить микробы кариеса во рту и защитить зубы","Сделать челюсть сильнее","Наполнить желудок"],
    answerIndex:1,
    explanation:"После еды в щелях и на поверхности зубов всегда остаются маленькие кусочки еды. Невидимые существа под названием микробы кариеса, которые живут у нас во рту, обожают эти остатки. Если оставить их там, микробы кариеса питаются ими и создают сильную кислоту, которая растворяет зубы. Из-за этой кислоты в зубах, которые должны быть самой твёрдой частью тела, понемногу появляются дырки, а когда доходит до нерва, боль так сильна, что ночью невозможно спать. Чистить зубы после еды — совершенно необходимое дело, чтобы убрать пищу микробов и защитить зубы." },
  { id:14, topic:"Профилактика травм", emoji:"👟",
    question:"Зачем носить обувь, когда идёшь на улице?",
    choices:["Чтобы ноги стали больше","Чтобы черви и микробы из земли не входили через кожу ног","Чтобы тренироваться в беге","Чтобы не пачкать одежду"],
    answerIndex:1,
    explanation:"Когда ты ходишь босиком по земле и грязи, крошечные существа, спрятанные в земле и слишком маленькие, чтобы их увидеть (личинки паразитов), и микробы могут пробить мягкую кожу подошв твоих ног и сами войти в тело. Черви, которые проникают, селятся в животе (кишечнике), крадут питательные вещества, которые ты ешь, делают тебя сильно малокровным, останавливают рост и забирают энергию. Обувь также защищает от тяжёлых травм из-за того, что наступаешь на битое стекло, острые камни или деревянные занозы. Всегда надевай обувь или сандалии, когда выходишь на улицу." },
  { id:15, topic:"Чистота", emoji:"👕",
    question:"Что будет, если постоянно носить грязную одежду?",
    choices:["Одежда станет прочнее","Кожа чешется или ты заболеваешь","Тело станет сильнее","Ничего не меняется"],
    answerIndex:1,
    explanation:"Если много дней подряд носить одежду, пропитанную потом или измазанную грязью, плесень и микробы питаются человеческим потом и кожным жиром на одежде и бурно размножаются в её волокнах. Поскольку эта грязная одежда всё время трётся о кожу, кожа может краснеть и опухать, сильно чесаться или заболеть с гноящимися язвами. Грязную одежду можно избавить от микробов, хорошо постирав её водой с мылом и высушив на солнце (ультрафиолетовые лучи). Всегда носить чистую одежду важно, чтобы защитить барьер кожи." },
  { id:16, topic:"Чистота", emoji:"🚿",
    question:"Чем полезно мыть тело?",
    choices:["Кожа становится чистой и ты предотвращаешь болезни кожи","Ты становишься выше","Волосы выпадают","Ты хочешь есть"],
    answerIndex:0,
    explanation:"Каждый день из человеческой кожи выходят невидимый жир (кожное сало) и пот, к ним примешиваются пыль и земля снаружи, и всё тело становится грязным. Если оставить эту грязь на много дней, плохие микробы размножаются на поверхности кожи, и могут появиться страшные фурункулы или ужасная болезнь, при которой кожа изъязвляется и гниёт. Регулярно мягко моя всё тело водой с мылом и убирая старый жир и грязь, ты сохраняешь кожу здоровой и сильной, создавая мощный барьер, который не пускает болезнь снаружи." },
  { id:17, topic:"Безопасная вода", emoji:"💧",
    question:"Когда есть только мутная вода, как пить её безопасно?",
    choices:["Пить как есть","Отфильтровать грязь тканью или песком, затем прокипятить на огне","Просто оставить на солнце и пить","Пить лишь немного"],
    answerIndex:1,
    explanation:"Когда всё, что ты можешь достать, — это мутная вода, питьё её как есть отправляет в тело огромное число микробов вместе с грязью и вызывает тяжёлую болезнь. Чтобы сделать её безопасной, нужны две мудрости. Сначала пропусти воду через тонкую чистую ткань или ёмкость, наполненную песком и мелкими камешками, чтобы отфильтровать грязь и крупные частицы и сделать воду прозрачной. Но прозрачности недостаточно — невидимые микробы всё ещё живы. Затем нужно поставить её на огонь и сильно кипятить, пока не пойдут пузырьки, чтобы жар уничтожил микробы, и тогда она наконец станет безопасной питьевой водой. С мудростью можно сделать спасающую жизнь воду даже из мутной." },
  { id:18, topic:"Младенцы", emoji:"🍼",
    question:"Какое питание лучше всего для младенца?",
    choices:["Коровье молоко (сырое)","Мамино молоко (грудное молоко)","Речная вода","Сахарная вода"],
    answerIndex:1,
    explanation:"Тело новорождённого младенца очень слабое и почти не имеет силы побеждать микробы болезней. Мамино молоко (грудное молоко) содержит не только идеальное питание, чтобы младенец рос, но и большое количество особого защитного вещества под названием иммунитет, которое оберегает его от болезней. К тому же грудное молоко выходит прямо из тела, поэтому никогда не касается грязной воды снаружи или микробов с посуды — оно самое чистое и безопасное в мире. Сырое молоко других животных, речная вода или сахарная вода могут испортить нежный желудок и кишечник младенца и отнять жизнь, поэтому их нельзя давать никогда." },
  { id:19, topic:"Профилактика болезней", emoji:"😷",
    question:"Что делать рядом с человеком, который сильно кашляет?",
    choices:["Держаться немного поодаль и отворачивать лицо при встрече","Глубоко вдохнуть перед ним","Пожать ему руку","Стоять прямо перед ним"],
    answerIndex:0,
    explanation:"Тяжёлые болезни дыхания, такие как туберкулёз, долго висят в воздухе, перенесённые крошечными невидимыми капельками, которые разлетаются, когда больной кашляет. Если глубоко вдохнуть рядом или долго быть близко, ты вдыхаешь эти микробы глубоко в лёгкие и можешь подхватить ту же тяжёлую болезнь. Когда кто-то сильно кашляет, дело не в том, чтобы быть злым или относиться к нему иначе; чтобы защитить себя, держи расстояние в несколько метров, а при встрече отворачивай лицо и тихо выдыхай — так вы оба бережёте друг друга." },
  { id:20, topic:"Свежий воздух", emoji:"🪟",
    question:"Как сохранить воздух в комнате чистым?",
    choices:["Плотно закрыть все двери и окна","Открыть окна и двери, чтобы сменить воздух","Всем вместе громко кричать","Ничего не меняется"],
    answerIndex:1,
    explanation:"Когда много людей собирается в маленькой закрытой комнате, микробы и вирусы, которые кто-то несёт, всё больше скапливаются в воздухе, пока воздух в комнате не наполнится микробами. Если долго быть в той комнате, все вдыхают грязный воздух и заболевают вместе (групповое заражение). Открыв окна и двери в двух или более местах, чтобы сменить свежий воздух снаружи на грязный воздух в комнате (проветривание), ты можешь выгнать микробы из воздуха и защитить здоровье всех, кто в комнате." },
  { id:21, topic:"Рычаг", emoji:"🪨",
    question:"Когда ты хочешь сдвинуть тяжёлый камень, врытый в землю, с помощью длинной палки, где нужно давить сильнее всего, чтобы сдвинуть его с наименьшим усилием?",
    choices:["В месте прямо рядом с камнем","Посередине палки","На самом дальнем конце палки, далеко от камня","Без разницы, где давить"],
    answerIndex:2,
    explanation:"Когда ты двигаешь что-то тяжёлое палкой, есть правило под названием «принцип рычага»: чем дальше ты от маленького камня, служащего опорой (точки опоры), тем меньше силы нужно, чтобы давить. Если давить рядом с камнем, палка не сдвинется, но если схватить самый дальний конец палки и давить, налегая своим весом, ты сможешь приподнять тяжёлый камень удивительно малой силой. Зная, как устроен инструмент, ты можешь увеличить собственную силу во много раз и легко выполнять тяжёлую работу." },
  { id:22, topic:"Рычаг", emoji:"⚖️",
    question:"Когда ты поднимаешь тяжёлый груз длинной палкой, где нужно положить маленький камень (точку опоры), поддерживающий палку, чтобы груз поднимался легче всего?",
    choices:["Прямо рядом с тяжёлым грузом","Прямо рядом с тем местом, где ты прикладываешь силу","Ровно посередине палки","Лучше вообще не класть камень"],
    answerIndex:0,
    explanation:"Когда ты поднимаешь что-то тяжёлое палкой, положение маленького камня-опоры (точки опоры) очень важно. Если положить эту опору прямо рядом с тяжёлым грузом, груз пройдёт лишь короткое расстояние, но сила, нужная тебе, чтобы поднять его, станет намного меньше. Наоборот, если камень-опора близко к тебе, как бы ты ни давил, груз не поднять. Когда хочешь сдвинуть что-то тяжёлое, помни мудрость: ставь опору близко к тому, что хочешь сдвинуть." },
  { id:23, topic:"Качение", emoji:"🪵",
    question:"Когда ты перемещаешь тяжёлый деревянный ящик, волоча его по земле, как сдвинуть его легче всего с наименьшим усилием?",
    choices:["Подложить под ящик несколько круглых твёрдых брёвен и катить его","Просто тянуть изо всех сил как есть","Полить ящик сверху водой","Бить ящиком с силой об пол"],
    answerIndex:0,
    explanation:"Когда ты волочишь что-то тяжёлое прямо по земле, сильно действует тормозящая сила под названием трение, возникающая там, где предмет трётся о землю, поэтому, чтобы сдвинуть его, нужна огромная сила. Но если подложить под ящик круглые твёрдые брёвна, движение из волочения превращается в качение брёвен. У качения тормозящая сила в десятки раз меньше, чем у волочения, поэтому даже один человек может плавно сдвинуть тяжёлый груз. Когда груз продвигается вперёд, ты берёшь брёвна, вышедшие сзади, и снова кладёшь их впереди — мудрость, которой человечество пользуется с древних времён." },
  { id:24, topic:"Наклон", emoji:"🛝",
    question:"Когда ты хочешь поднять тяжёлый груз на высокий помост примерно по грудь взрослому, какой способ перемещения меньше всего нагружает твоё тело?",
    choices:["Встать перед помостом и поднять груз прямо вверх изо всех сил","Прислонить к помосту длинную доску под наклоном, сделав пандус, и толкать груз вверх","Бросать груз в помост издалека","Срезать высоту помоста, сделав его ниже"],
    answerIndex:1,
    explanation:"Если ты пытаешься поднять тяжёлый груз прямо вверх, ты в лоб противостоишь силе, тянущей вещи к земле (гравитации), поэтому приходится держать весь вес только мышцами, что повреждает спину и руки. Здесь, если прислонить к помосту длинную доску под наклоном, сделав пандус (наклонную плоскость), доска возьмёт на себя большую часть веса груза. По пандусу путь, который ты проходишь, удлиняется, но силу, нужную, чтобы толкать груз, можно уменьшить более чем вдвое. Когда несёшь вещи наверх, всегда придумывай, как сделать пандус." },
  { id:25, topic:"Блок", emoji:"🪣",
    question:"Когда ты вытягиваешь верёвкой тяжёлое ведро воды из глубокого колодца, что станет легче, если установить на перекладине над колодцем круглое крутящееся колесо (блок) и перекинуть через него верёвку?",
    choices:["Вес воды станет вдвое легче","Количество воды само увеличится","Можно поднять воду, просто потянув верёвку вниз","Верёвка никогда не порвётся"],
    answerIndex:2,
    explanation:"Когда ты перекидываешь верёвку через круглое колесо над колодцем (неподвижный блок), на самом деле вес воды легче не становится. Но замечательное в этом устройстве то, что оно меняет направление, в котором ты прикладываешь силу. Если тянуть верёвку прямо вверх, приходится поднимать её только силой рук и спины; но если перекинуть верёвку через круглое колесо и тянуть вниз, ты можешь налечь на верёвку всем весом тела. Возможность использовать собственный вес, чтобы легко и безопасно поднимать тяжёлую воду, — вот мудрость этого круглого колеса." },
  { id:26, topic:"Ворот", emoji:"🔄",
    question:"Когда ты хочешь повернуть винт, который никак не поворачивается, или тяжёлый колодезный ворот, как повернуть его легче всего?",
    choices:["Поворачивать короткой тонкой палочкой","Сделать рукоятку большой и длинной и поворачивать её","Поворачивать только кончиками пальцев, без инструмента","Сильно бить по винту молотком"],
    answerIndex:1,
    explanation:"Когда ты хочешь повернуть ось в центре, если насадить на эту ось большую круглую рукоятку или длинную ручку, можно создать большую вращающую силу малым усилием. Это называется принципом ворота (колеса и оси). Тонкую часть не сдвинуть, поворачивая её прямо пальцами, но когда ты поворачиваешь большую внешнюю рукоятку, путь, который проходит твоя рука, удлиняется, а сила на оси становится во много раз больше. Машина, наматывающая верёвку колодца, дверная ручка дома, винты на инструментах — всё, что вращается вокруг тебя, использует эту мудрость." },
  { id:27, topic:"Центр тяжести", emoji:"🏺",
    question:"Есть люди, которые ловко ходят, неся тяжёлый кувшин с водой или дрова на голове. Почему они могут проходить большие расстояния, не повреждая шею и спину?",
    choices:["Потому что ходят, сильно сгибая тело вперёд или назад","Потому что держат спину идеально прямо и помещают центр груза (его центр тяжести) прямо над своими костями","Потому что всё время сильно трясут грузом на голове","Потому что все рождаются с более толстыми костями шеи, чем у других"],
    answerIndex:1,
    explanation:"Когда ты несёшь тяжёлый груз в руках, нагрузка ложится лишь на одну сторону тела, и мышцы быстро устают. Но если выпрямить спину идеально и поместить груз прямо над головой, вес центра груза (его центр тяжести) проходит прямо вниз по столбу костей — от головы к шее, потом к позвоночнику — и уходит в землю. Поскольку вес держат крепкие кости, а не мышцы, ты можешь безопасно нести его на большие расстояния, не тратя мышечную силу, пока сохраняешь равновесие. Держать вещи близко к центральной оси тела — важная мудрость, чтобы не пораниться." },
  { id:28, topic:"Давление", emoji:"🦶",
    question:"Когда ты идёшь по грязной дороге, где после дождя — глубокая грязь и ноги вязнут, как идти легче, не проваливаясь?",
    choices:["Идти на цыпочках, делая подошвы ног как можно меньше","Привязать к подошвам ног плоскую большую деревянную доску и идти","Просто громко кричать и перебегать","Нести много поклажи, чтобы стать тяжелее"],
    answerIndex:1,
    explanation:"Вес, давящий на землю, тем сильнее сосредотачивается в одной точке и тем глубже вонзается, как игла, чем меньше площадь, которая его касается. Это называется давлением. Если встать на цыпочки, площадь уменьшается, поэтому проваливаешься ещё глубже. Наоборот, если привязать к подошвам плоскую большую доску, твой вес распределяется по большой площади, поэтому сила, давящая на землю вниз, ослабевает, и можно идти по грязи, не проваливаясь. Делать основание тяжёлого здания широким и плоским — та же мудрость для распределения давления." },
  { id:29, topic:"Тележки", emoji:"🛒",
    question:"Когда ты хочешь нагрузить двухколёсную тележку множеством тяжёлой поклажи и тянуть её, куда положить тяжёлое, чтобы было легче всего тянуть?",
    choices:["Прямо рядом с твоими руками, у ручки","На самом заднем конце тележки","Прямо над осью колёс","Без разницы, куда грузить"],
    answerIndex:2,
    explanation:"Когда ты тянешь тележку, вес на твоих руках резко меняется в зависимости от того, куда ты кладёшь груз. Если положить тяжёлую поклажу рядом с руками, ты в итоге бежишь, поднимая вес груза прямо руками, и быстро устаёшь. Если слишком далеко назад, тележка опрокидывается назад, что опасно. Правильный ответ — прямо над осью колёс. Если положить тяжёлое сюда, крепкие колёса и земля держат весь вес, поэтому на руки почти не приходится веса. Поскольку нужна лишь сила тянуть вперёд, можно очень легко везти большой груз." },
  { id:30, topic:"Лезвие", emoji:"🔪",
    question:"Когда ты точишь остриё топорика для колки дров или кухонного ножа для резки еды, потерев его о камень (точильный камень), почему он начинает резать лучше?",
    choices:["Потому что остриё лезвия становится тоньше и острее, и сила сосредотачивается в одной точке","Потому что лезвие нагревается и плавит еду","Потому что лезвие становится тяжелее","Потому что лезвие становится округлым"],
    answerIndex:0,
    explanation:"То, что что-то режется лезвием, происходит потому, что сила, приложенная человеком, сосредотачивается на крайне узком месте острия лезвия и продавливает предмет. Когда лезвие стареет и округляется, сила распределяется по большой площади, поэтому, как ни дави, оно не режет. Точить лезвие — это работа, при которой сточенное округлое остриё делают как можно тоньше и острее. Как только остриё тонкое, даже малая сила создаёт в этой точке огромное давление, поэтому можно лёгким движением рассечь твёрдые дрова или еду. Уход за инструментами — основа экономии своих сил." },
  { id:31, topic:"Трение", emoji:"👟",
    question:"Когда ты идёшь по склону или по мокрым камням, что меньше скользит и безопаснее: гладкая скользкая обувь или обувь с глубокими шипастыми канавками на подошве?",
    choices:["Гладкая ровная обувь","Обувь с глубокими шипастыми канавками на подошве","Без разницы, что надеть","Без обуви вообще скользишь меньше"],
    answerIndex:1,
    explanation:"Когда подошва обуви трётся о землю, там действует тормозящая сила под названием трение, не давая тебе скользить. Если подошва гладкая, между ней и землёй не действует никакого торможения, и ты легко поскальзываешься и падаешь, особенно там, где есть вода или грязь. Если на подошве глубокие шипастые канавки, эти канавки крепко цепляются за неровности земли и создают сильное торможение. Поскользнуться и упасть может привести к тяжёлой травме, но, зная, как работает трение — выбирая обувь с канавками на скользкой поверхности или твёрдо ставя всю подошву на землю, — ты можешь действовать безопасно." },
  { id:32, topic:"Плавучесть", emoji:"⛵",
    question:"Маленький камешек тонет в воде, и всё же деревянный корабль, в тысячи раз тяжелее и больше, может плыть по воде. Почему?",
    choices:["Потому что корабль сделан в форме чаши и удерживает внутри много воздуха и воды","Потому что на корабль дует много ветра","Потому что на его дне нарисованы волшебные камни","Потому что корабль сделан из масла, которое легче воды"],
    answerIndex:0,
    explanation:"На предмет в воде действует загадочная сила под названием выталкивающая сила (сила Архимеда), толкающая его вверх настолько, сколько воды он вытесняет. Камешек внутри плотный и тяжёлый, поэтому камень тяжелее воды, которую он вытесняет, и тонет. Но большой корабль имеет форму чаши, и внутри удерживает много воздуха. Если смотреть в целом, он становится очень лёгким для своего размера, поэтому сила воды, толкающая снизу вверх, становится сильнее, и даже большой корабль может плыть по воде, не переворачиваясь." },
  { id:33, topic:"Треугольники", emoji:"🔺",
    question:"Когда ты строишь дом или мост из дерева или железа, почему сборка каркаса в форме треугольников делает здание очень прочным и трудноразрушимым?",
    choices:["Потому что требуется больше материала, чем на квадрат","Потому что у треугольника есть свойство: его форма никогда не искажается, даже когда сверху прикладывают сильную силу","Потому что треугольники легче пропускают ветер","Потому что это древняя форма, используемая как оберег от богов"],
    answerIndex:1,
    explanation:"Здание из столбов, собранных только в квадраты, легко рушится, со стыками, вяло сгибающимися, когда сверху или сбоку прикладывается сильная сила или сотрясение землетрясения. Но если добавить внутри этого квадрата один косой стержень, сделав треугольник (ферменную конструкцию), то с какой бы стороны ни шла сила, стержни тянут и подпирают друг друга, и форма совсем не искажается. Если посмотреть на большие мосты мира или на изнанку крыш зданий, эти треугольники всегда тонко собраны вместе. Это замечательная строительная мудрость: даже с малым количеством материала, лишь продумав форму, можно сделать вещь во много раз прочнее." },
  { id:34, topic:"Инерция", emoji:"🐎",
    question:"Когда бегущая лошадь или тележка резко тормозит и встаёт намертво, что происходит с поклажей и людьми, едущими сверху?",
    choices:["Опрокидываются назад как есть","С силой вылетают вперёд","Подпрыгивают прямо вверх на месте","Ничего не происходит; тоже встают намертво"],
    answerIndex:1,
    explanation:"Во вселенной есть загадочная сила под названием инерция: движущаяся вещь стремится продолжать двигаться с той же скоростью. Даже когда лошадь или тележка внезапно останавливается, люди и поклажа сверху всё ещё стремятся продолжать движение вперёд. Поэтому, если крепко не упереться ногами или не привязать груз верёвкой, тебя с силой выбрасывает вперёд и сильно ранит. Когда останавливаешь что-то движущееся или едешь на быстром транспорте, нужно помнить, что эта сила, стремящаяся выбросить вещи вперёд, действует всегда, и подготовиться ради своей безопасности." },
  { id:35, topic:"Ножницы", emoji:"✂️",
    question:"Когда ты хочешь разрезать твёрдую ветку или толстую ткань ножницами, в каком месте лезвия зажать, чтобы резать легче всего с наименьшим усилием?",
    choices:["На самом кончике лезвия","У основания лезвия (ближе всего к винту или шарниру)","Посередине лезвия","Нужная сила одинакова, где ни режь"],
    answerIndex:1,
    explanation:"Ножницы тоже очень удобный инструмент, использующий принцип рычага, который мы изучали. Винт, где два лезвия скрещиваются и закреплены, служит опорой (точкой опоры). Чем ближе к этому винту-опоре ты режешь, тем во много раз сильнее становится сила, которую твоя сжимающая рука передаёт лезвию. Поэтому с твёрдым, что не режется, попытка резать кончиком ножниц лишь причиняет боль руке, но если зажать глубоко у основания лезвия, можно отрезать удивительно малой силой. Знай особенности своих инструментов и используй самое эффективное место." },
  { id:36, topic:"Гравитация", emoji:"🍎",
    question:"Почему, если уронить маленький камешек на ногу с высоты колена и с высокой крыши дома, тот, что падает с крыши, причиняет более тяжёлую травму?",
    choices:["Потому что камень становится холоднее наверху на крыше","Потому что гравитация, сила, тянущая вещи к земле, делает камень всё быстрее, чем длиннее падение, поэтому удар при столкновении сильнее","Потому что камень наверху становится больше в размере","Потому что воздух толкает камень вниз"],
    answerIndex:1,
    explanation:"Всё на земле постоянно тянет сила под названием гравитация, влекущая к земле. Для вещи наверху, чем длиннее падение, тем больше её продолжает тянуть гравитация и тем быстрее она разгоняется (ускоряется). Разогнавшийся предмет создаёт огромную разрушительную силу (энергию) в тот миг, когда ударяется о землю или твоё тело. С высоты колена только больно, но то, что падает с высокой крыши или обрыва, даже маленький камень или инструмент, становится оружием, способным отнять жизнь человека. Когда работаешь рядом с высоким местом, нужно проверить, нет ли кого внизу, и крайне осторожно не уронить ничего." },
  { id:37, topic:"Равновесие", emoji:"⚖️",
    question:"Когда ты несёшь на плече длинный шест (коромысло) с двумя тяжёлыми кувшинами воды, подвешенными спереди и сзади, как идти легко, не повреждая плечо?",
    choices:["Сделать передний груз очень тяжёлым, а задний лёгким","Сделать передний и задний грузы абсолютно одинакового веса и положить на плечо самую середину шеста","Не класть шест на плечо; нести только руками","Бросать грузы на землю поочерёдно на бегу"],
    answerIndex:1,
    explanation:"Когда ты несёшь грузы, подвешенные с обеих сторон длинного шеста, если передний и задний веса неравны, шест наклоняется в одну сторону, и приходится изо всех сил удерживать его руками. От этого быстро устаёт не только плечо, но и руки, и спина. Правильный ответ — сделать передний и задний грузы абсолютно одинаковыми по равновесию. Тогда вес ложится равномерно прямо над плечом через коромысло, и можно нести тяжёлые грузы, просто идя, не используя лишних мышц, чтобы бороться с наклоном. Если один груз неизбежно легче, отрегулируй равновесие, сдвинув верёвку лёгкой стороны к концу шеста." },
  { id:38, topic:"Сопротивление воздуха", emoji:"🪂",
    question:"У тебя два листа бумаги одинакового размера и одинакового веса. Один оставлен плоским листом, другой сжат рукой в плотный комок. Когда ты роняешь их одновременно с высоты, какой раньше достигнет земли?",
    choices:["Плоский лист как есть","Бумага, сжатая в плотный комок","Оба достигнут точно одновременно","Каждый раз по-разному, в зависимости от ветра"],
    answerIndex:1,
    explanation:"Даже для вещей одинакового веса, когда они падают сквозь воздух, действует тормозящая сила под названием сопротивление воздуха, ведь воздух мешает. Плоский лист бумаги имеет большую площадь, поэтому ловит много воздуха под собой и падает лишь медленно, как парашют. Но бумага, сжатая в маленький комок, касается воздуха очень малой площадью, поэтому почти не получает торможения и падает быстро, влекомая прямо вниз гравитацией. То, что ветряк крутится от ветра или что зонт чуть не уносит в ветреный день, тоже связано с этой тормозящей силой воздуха." },
  { id:39, topic:"Упругость", emoji:"🏹",
    question:"Когда ты изо всех сил сгибаешь твёрдый крепкий бамбук или гибкую ветку дерева, а потом резко отпускаешь, она с силой возвращается к исходной форме. Для чего можно использовать это свойство (упругость), чтобы сделать полезный в быту инструмент?",
    choices:["Холодильник, чтобы еда не гнила","Лук и стрелы, чтобы пускать стрелу в далёкую добычу, или ловушку, выбрасывающую тяжёлое","Фильтр, чтобы очищать воду","Инструмент, чтобы красить одежду в белый"],
    answerIndex:1,
    explanation:"У резины и пружин, а также у бамбука и веток деревьев есть загадочное свойство под названием упругость: когда ты прикладываешь силу, их форма сгибается, а когда отпускаешь, они стремятся вернуться к исходной форме с огромной скоростью. Пока ты держишь её согнутой рукой, сила, приложенная человеком, на миг запасается внутри этого инструмента как энергия. В тот миг, когда ты отпускаешь, эта запасённая сила высвобождается разом, поэтому можно пустить стрелу во много раз дальше или привести в действие ловушку, чем бросая только рукой. Используя эту силу, которой обладают растения природы, человечество с древних времён делает орудия для охоты и быта." },
  { id:40, topic:"Смазка", emoji:"🛢️",
    question:"Колёса тележки или петля двери стали при каждом движении издавать противный скрип и стали тугими. Если капнуть сюда несколько капель масла, почему они снова начинают двигаться легко?",
    choices:["Потому что масло плавит железо и делает его легче","Потому что масло застывает и становится клеем","Потому что масло проникает в зазор между металлом и металлом и резко уменьшает тормозящую силу трения","Потому что запах масла отгоняет насекомых"],
    answerIndex:2,
    explanation:"Когда машина или инструмент движется, есть места, где металл сильно и напрямую трётся о металл. Там действует очень сильная тормозящая сила под названием трение, и если оставить как есть, оно стирается и ломается, или для движения нужна огромная сила. Когда ты наносишь масло, в крошечном зазоре металла образуется тонкая плёнка масла и не даёт им тереться напрямую. Поскольку тормозящая сила разом исчезает, инструмент движется поразительно плавно и с малой силой. Стоит лишь нанести на инструмент немного пищевого или растительного масла, как он служит дольше и сильно снижает расход человеческих сил." },
  { id:41, topic:"Молния", emoji:"⚡",
    question:"Когда гремит гром и ты на улице, куда безопаснее всего спрятаться?",
    choices:["Прямо под высоким деревом","Посреди широкого открытого поля","Внутри прочного здания или машины, окружённой металлом","Стоя, держа большой зонт"],
    answerIndex:2,
    explanation:"Молния имеет сильную склонность бить в высокие предметы. Поэтому, если ты стоишь один посреди открытого поля, ты становишься самым высоким острым предметом вокруг, и опасность прямого удара становится очень высокой. Кроме того, стоять прямо под высоким деревом опасно: молния, ударившая в дерево, может перескочить на твоё тело, явление под названием боковой разряд, и причинить смертельную травму. Самые безопасные места — внутри прочного бетонного здания или внутри машины, окружённой металлическими листами. Даже если молния ударит в машину, электричество пройдёт по наружному металлу и уйдёт в землю, поэтому люди внутри полностью в безопасности." },
  { id:42, topic:"Наводнения", emoji:"🌊",
    question:"При сильном дожде дорога превратилась в реку, и тебе ничего не остаётся, кроме как идти по воде, чтобы эвакуироваться. Что безопаснее всего надеть на ноги?",
    choices:["Босиком","Сандалии","Обувь, крепко завязанную шнурками","Резиновые сапоги"],
    answerIndex:2,
    explanation:"Дно затопленной дороги скрывает много невидимых опасностей: битое стекло, острые банки, открытые люки. Босиком или в сандалиях ты легко раня ноги и больше не можешь двигаться. Резиновые сапоги кажутся хорошими, но как только вода зальётся сверху, они становятся тяжёлыми, как водяные подушки, ноги совсем не поднимаются, и это мешает идти или приводит к утоплению. Безопаснее всего обувь, которая не слетает и с твёрдой подошвой: кроссовки, крепко завязанные шнурками. Они не тяжелеют даже при попадании воды и защищают твои ноги, позволяя идти уверенно." },
  { id:43, topic:"Эвакуация", emoji:"⛰️",
    question:"Пришло наводнение от сильного дождя или цунами, и вода подступает к ногам. В каком направлении правильно бежать?",
    choices:["Вниз по течению, где вода течёт быстро (низкое место)","На ближний высокий холм или гору, или на верхний этаж прочного здания (высокое место)","В дом родственника, который далеко","В подвал своего дома (ниже уровня земли)"],
    answerIndex:1,
    explanation:"При наводнении или цунами вода накапливается с огромной силой, начиная с самых низких мест. Если спрятаться в подвале ниже уровня земли, вода хлынет через вход разом, ты не сможешь выйти и утонешь. Кроме того, пытаясь убежать далеко, блуждая туда-сюда, можно столкнуться с принесёнными деревьями или машинами, или потерять опору под ногами от бурного потока и быть унесённым. Когда вода подступает, правило не в том, чтобы идти далеко, а в том, чтобы направиться к ближайшему высокому месту от того, где ты сейчас. Подняться на ближний холм или гору, или на 2-й или 3-й этаж прочного бетонного здания, и ждать, пока вода спадёт, — это выбор, который защищает твою жизнь." },
  { id:44, topic:"Тепловой удар", emoji:"🥵",
    question:"В очень жаркий день, когда солнечный свет крайне силён, что важнее всего для предотвращения болезни, при которой тело перегревается и ты падаешь (тепловой удар)?",
    choices:["Терпеть, не пить воду","Намазать всё тело холодной грязью","Отдыхать в тени и пить безопасную воду понемногу, много раз","Много бегать, чтобы пропотеть"],
    answerIndex:2,
    explanation:"Если долго находиться в очень жарком месте, вода и соль из твоего тела выходят с потом, и тело больше не может само снижать свой жар. Это страшное состояние под названием тепловой удар. Чтобы его предотвратить, важно найти прохладную тень, куда не падает прямой солнечный свет, и дать телу отдохнуть. И нужно пить безопасную, прокипячённую и остуженную воду понемногу, много раз, ещё до того как почувствуешь жажду. Чем пить много разом, лучше пить частыми маленькими глотками, так тело хорошо впитывает воду, и ты можешь провести день бодро и безопасно даже под сильным солнцем." },
  { id:45, topic:"Землетрясения", emoji:"🪑",
    question:"Когда происходит землетрясение и земля и твой дом начинают сильно трястись, что нужно сделать в комнате в первую очередь?",
    choices:["В панике выбежать наружу","Спрятаться под прочным столом и защитить голову и тело","Плотно закрыть окна и смотреть наружу","Запихнуть много вещей в сумку"],
    answerIndex:1,
    explanation:"Когда происходит землетрясение, самое опасное — это падение предметов сверху и опрокидывание мебели. Если в панике выбежать наружу, с верхних частей зданий могут упасть битое стекло и черепица и ударить по голове — очень высокий риск серьёзной травмы. Почувствовав тряску, сначала заберись прямо там под прочный стол или кровать, крепко схватись за ножки стола и защити свою голову и тело. Если негде спрятаться, плотно прикрой голову подушкой, сумкой или собственными руками, сожмись посреди комнаты, где на тебя не упадёт мебель, и тихо жди, пока тряска полностью не прекратится, — это безопаснее всего." },
  { id:46, topic:"Молния", emoji:"⚡",
    question:"Когда гром гремит совсем близко, какое действие на улице самое опасное?",
    choices:["Держать пластиковую игрушку","Держать длинный металлический шест или удочку, подняв высоко к небу","Носить одежду из ткани","Носить деревянную обувь"],
    answerIndex:1,
    explanation:"Молния имеет страшную склонность бить сосредоточенно в предметы, которые высокие и с острым кончиком. Поэтому, если на улице ты держишь длинный металлический шест, удочку или длинный зонт, выставив высоко к небу, это становится как антенна, призывающая молнию, и она бьёт прямо в тебя. Услышав раскаты грома, немедленно положи любой длинный шест, что держишь, горизонтально на землю, опусти собственную позу как можно ниже и присядь, опустив голову. А затем сразу эвакуируйся в безопасное здание." },
  { id:47, topic:"Оползни", emoji:"⚠️",
    question:"Когда около горы беспрерывно идёт сильный дождь, какой опасный признак того, что гора может обрушиться (оползень)?",
    choices:["Вода в реке вдруг становится чёрной и мутной, и плывёт много щепок","Маленькие камешки понемногу скатываются с горы","Из глубины земли слышен странный гул, похожий на стон земли","Всё это — опасные признаки"],
    answerIndex:3,
    explanation:"Когда сильный дождь льёт на гору, почва впитывает огромное количество воды, и в какой-то момент обрыв или вся гора обрушивается разом — большое бедствие под названием оползень или сель. Прямо перед тем, как они случаются, природа всегда подаёт несколько предупреждающих знаков. Внезапное помутнение речной воды и увеличение плавника — доказательство того, что выше почва начинает обрушиваться. Кроме того, если с горы падают камешки или из земли слышен жуткий звук — это сигнал, что вся гора вот-вот придёт в движение. Если ты находишь или чувствуешь хоть один из этих знаков, ты должен покинуть это место на секунду раньше и бежать в высокое, прочное место." },
  { id:48, topic:"Наводнения", emoji:"🦯",
    question:"Когда тебе приходится идти по воде наводнения, по дороге, где грязь делает землю совершенно невидимой, как нужно идти, чтобы быть в безопасности?",
    choices:["Бежать на полной скорости, чтобы быстро спастись","Длинным шестом простукивать и проверять, что земля безопасна, шаг за шагом","Закрыть глаза и идти прямо вперёд","Снять всю одежду и плыть вперёд"],
    answerIndex:1,
    explanation:"После наводнения вода на дороге мутно-коричневая от смешанной грязи и мусора, поэтому ты совсем не видишь, какая под ногами земля. На самом деле под водой крышка люка могла слететь, оставив глубокую яму, или землю могло размыть в глубокую канаву. Если бежать или идти, не замечая, можно в мгновение упасть в глубокую яму и уйти под воду. Идя по воде, всегда держи длинный, прочный шест как трость и, прежде чем сделать следующий шаг, простучи землю шестом, чтобы проверить, нет ли ямы, продвигаясь медленно и осторожно, — это способ ходьбы, который защищает твою жизнь." },
  { id:49, topic:"Торнадо", emoji:"🌪️",
    question:"Когда приближается торнадо (сильный ветер, кружащийся с огромной скоростью), где в доме безопаснее всего спрятаться?",
    choices:["Прямо рядом с окном с хорошим видом наружу","На крыше, где ветер приятен","Прочная комната без окон, или туалет или шкаф в центре дома","Лёжа на большой кровати"],
    answerIndex:2,
    explanation:"Торнадо — самый яростный порыв на Земле, достаточно сильный, чтобы сорвать крышу дома или поднять в воздух большие деревья и машины. Когда приближается торнадо, самое страшное — это летящий предмет, пробивающий оконное стекло, и осколки стекла, разлетающиеся по всей комнате с огромной скоростью. Поэтому быть рядом с окном означает серьёзную травму. Самое безопасное место — где стены толще всего и нет совсем никаких окон: туалет в центре дома, прочная комната или шкаф. Запрись там, прикрой голову подушкой или одеялом, свернись и тихо жди, пока буря пройдёт, — это правильный способ спрятаться." },
  { id:50, topic:"Пожар", emoji:"🔥",
    question:"Когда вспыхивает пожар и в комнате скапливается много дыма, как нужно выбираться наружу?",
    choices:["Вытянуться во весь рост и бежать на полной скорости","Принять низкую позу, ползя по полу, прикрыть рот тканью и выбираться","Закрыть все окна, чтобы запереть дым","Накрыться большим одеялом и спать в кровати"],
    answerIndex:1,
    explanation:"В дыме, который образуется при пожаре, содержится много вредного яда (например, угарного газа), от которого человек теряет сознание в тот же миг, как вдохнёт. Поскольку дым горячий, в комнате он скапливается сначала от потолка (высокой части), а сравнительно чистый воздух остаётся последним у пола. Поэтому, если вытянуться во весь рост, ты вдохнёшь самый густой ядовитый дым прямо и больше не сможешь двигаться. Выбираясь, держи низкую позу с грудью у пола, плотно прижми мокрую ткань или одежду ко рту и носу, дыши воздухом у пола и быстро выберись наружу, — это правильный способ выбраться." },
  { id:51, topic:"Цунами", emoji:"🌊",
    question:"Когда ты у моря и чувствуешь сильное землетрясение, что важнее всего сделать немедленно?",
    choices:["Пойти посмотреть, есть ли в море рыба","Вернуться домой, чтобы собрать все свои вещи","Уйти от берега и быстро подняться на высокую гору или прочную возвышенность","Сидеть неподвижно на песчаном пляже"],
    answerIndex:2,
    explanation:"Когда под морем происходит большое землетрясение, морское дно сильно сдвигается, и вся окружающая вода накатывает огромной волной, как стена, — большое бедствие под названием цунами. В отличие от обычных волн, у цунами огромный вес и разрушительная сила, способные смыть здания и дома в мгновение. Кроме того, перед приходом цунами прилив может вдруг отступить и обнажить песок, но если пойти посмотреть на это ради забавы, в следующий миг тебя поглотит большая волна. Почувствовав тряску у моря, не бери ничего, уйди от моря на секунду раньше и беги на высокий холм или гору, или верхний этаж прочного здания. Как только ты увидишь волну, убежать уже не успеешь." },
  { id:52, topic:"Холод", emoji:"🧥",
    question:"Когда ты можешь заблудиться в очень холодном месте зимой, какое действие лучше всего, чтобы сохранить тепло тела и выжить?",
    choices:["Пить много холодной воды","Оставаться в мокрой одежде как есть","Спрятаться там, где не достаёт ветер, и надеть много слоёв одежды или ткани","Лечь спать прямо на снег"],
    answerIndex:2,
    explanation:"Тело человека, если его температура падает слишком сильно, больше не может двигаться и теряет жизнь (переохлаждение). Особенно ветер и мокрая одежда — опасные враги, которые крадут тепло из тела в мгновение. Чтобы защититься в холодном месте, главный приоритет — спрятаться там, где ветер совсем не достаёт, например за большим камнем или внутри здания. Затем, если одежда мокрая, обязательно переоденься в сухую и надень много слоёв одежды, ткани или бумаги, что у тебя есть. Слои ткани создают между собой слой тёплого воздуха — волшебную стену, не выпускающую тепло твоего тела. Сон прямо на снегу крадёт тепло, поэтому подстелить на землю траву или картон, чтобы сесть, — тоже важная мудрость." },
  { id:53, topic:"Вулканы", emoji:"🌋",
    question:"Когда близкий вулкан (гора, что извергает горячий огонь и грязь) внезапно извергается, как защититься от пепла и камней, летящих с неба?",
    choices:["Смотреть на небо и внимательно наблюдать, что падает","Зайти в прочное здание (например, бетонный дом) и прикрыть рот и нос тканью","Прыгнуть в ближнюю реку и плыть","Бежать на полной скорости в сторону горы"],
    answerIndex:1,
    explanation:"Когда вулкан извергается, с вершины с неба падают тяжёлая раскалённая докрасна лава и большие камни с пугающей скоростью. Если они попадут по голове, это смертельно, поэтому надо сразу спрятаться внутри прочного здания из бетона или подобного. Кроме того, вулканический пепел, что извергает вулкан, — не обычный песок, а как мелко раздробленные стеклянные шипы. Вдохнуть его — повредить лёгкие так, что не сможешь дышать, а если попадёт в глаза — от сильной боли не сможешь их открыть. Спрятавшись в здании, плотно закрой окна, плотно прикрой рот и нос маской или смоченной водой тканью и защити себя, чтобы никогда не вдохнуть грязный пепел." },
  { id:54, topic:"Туман", emoji:"🌫️",
    question:"Когда туман (белая дымка, расходящаяся в воздухе) становится очень густым и ты совсем не видишь впереди, что самое опасное при ходьбе?",
    choices:["Остановиться там, где стоишь","Перестать слышать звуки вокруг","Не видеть собственного положения и опасных мест, как обрывы, и из-за этого заблудиться или упасть","Что одежда немного отсыреет"],
    answerIndex:2,
    explanation:"Когда образуется густой туман, даже пейзаж всего в нескольких метрах впереди становится белым, и ты ничего не видишь. Если в таком состоянии заставлять себя идти дальше, твоё чувство направления — куда ты идёшь — полностью парализуется, и это может привести к серьёзным происшествиям: забрести в опасный глубокий лес, или не заметить глубокий обрыв или реку прямо перед собой и рухнуть вниз головой до смерти. Когда не видишь впереди, нельзя ни в коем случае идти напролом. Самая безопасная защита — остановиться там, где стоишь, в месте с надёжной опорой, например посреди безопасной широкой дороги, и тихо ждать, пока туман не рассеется и ты снова хорошо не увидишь вокруг." },
  { id:55, topic:"Обвал", emoji:"🪨",
    question:"Когда ты у высокой земляной стены (обрыва) после того, как прошёл сильный дождь, чего нужно непременно остерегаться?",
    choices:["Дождевая вода может впитаться в обрыв, и он может внезапно обрушиться (обвал), поэтому немедленно уйди","Залезть на верх обрыва и весело играть","Поставить палатку прямо под обрывом и спать","Лить много воды на стену обрыва"],
    answerIndex:0,
    explanation:"Обрыв или старый земляной склон после сильного дождя имеет огромное количество воды, накопленной до предела внутри почвы, и находится в очень хрупком, губчато-раскисшем состоянии. Даже после того как дождь прекратится, спустя от нескольких часов до нескольких дней, часто случается обвал, когда вся стена внезапно обрушивается, словно взрываясь, совсем без звука. Если играть или спать у подножия обрыва, тебя в мгновение завалит многими тоннами тяжёлой земли, и спасти уже не смогут. Во время сильного дождя и в течение нескольких дней после того, как дождь прекратится, всегда соблюдай правило: никогда не подходи к высокой земляной стене или обрыву, немедленно уходи." },
  { id:56, topic:"Эвакуация", emoji:"🏃",
    question:"Когда река у твоего дома при сильном дожде поднимается всё выше и вот-вот выйдет из берегов, когда нужно начинать эвакуацию?",
    choices:["После того как вода вошла в дом","Рано, пока ещё светло на улице и на дороге не скопилась вода, пока безопасно","Тихо ждать, пока речная вода полностью не выйдет из берегов","Подумать об этом после того, как ляжешь в постель спать"],
    answerIndex:1,
    explanation:"Пытаться эвакуироваться после того, как река вышла из берегов и вода начала скапливаться на дороге, — самое опасное, слишком позднее решение. Когда вода скапливается до высоты колена на дороге, даже взрослого мужчину сносит сильной силой воды, и он совсем не может идти. Кроме того, когда стемнеет ночью, ты больше не различаешь, где дорога, а где река, и падаешь в реку и тебя уносит по пути к эвакуации. Самое правильное время начинать эвакуацию — пока ещё светло на улице и у ног не скопилась вода, пока безопасно. Как только ты почувствуешь хоть малую опасность от поднимающейся реки, сведи вещи к минимуму и отправляйся пораньше к высокому, безопасному убежищу, — это мудрость, которая надёжно защищает твою жизнь." },
  { id:57, topic:"Удар током", emoji:"🔌",
    question:"После землетрясения или сильного дождя ты находишь в доме порванный электрический провод, который искрит. Почему его нельзя ни в коем случае трогать?",
    choices:["Потому что руки испачкаются чёрной грязью","Потому что сильное электричество, текущее в проводе, перейдёт в твоё тело и причинит серьёзную травму, например остановку сердца (удар током)","Потому что провод холодный, как лёд","Потому что комната станет совсем тёмной"],
    answerIndex:1,
    explanation:"Из порванного провода или из намокшего водой электроприбора может вытекать очень сильное электричество, невидимое человеческому глазу. Если ты тронешь его рукой, не зная, электричество провода в мгновение пронзит твоё тело и уйдёт в землю. Это называется удар током. Получив сильное электричество, ты не только обожжёшь тело, но и можешь остановить сердце наповал — смертельное происшествие в мгновение. Особенно когда твоё тело или руки мокрые от воды, электричество переходит в тело во много раз легче, что ещё опаснее. Если ты находишь искрящий провод или оборванный провод, никогда не подходи, не трогай и сообщи взрослому." },
  { id:58, topic:"Тайфуны", emoji:"🌀",
    question:"Когда дует яростный сильный ветер (тайфун или циклон), почему выходить наружу опасно настолько, что под угрозой жизнь?",
    choices:["Потому что воздух снаружи не очень вкусный","Потому что вывески магазинов, черепица с крыш и большие ветки деревьев летят и бьют по голове","Потому что любимая одежда пачкается грязью","Потому что от сильного ветра по всему телу полнеешь"],
    answerIndex:1,
    explanation:"Во время яростной бури, как тайфун или циклон, сила ветра становится далеко за пределами того, что представляют люди. Быть унесённым самим ветром опасно, но самое страшное — это всё, что есть в городе, становится оружием и летит на тебя. Тяжёлые вывески магазинов, твёрдая черепица с крыш, сломанные ветки деревьев и прочее летят сбоку со скоростью, как острый нож или пуля. Если хоть одно из этого ударит по твоему телу, это смертельная травма. Пока слышен звук сильного ветра, какое бы дело у тебя ни было, нельзя ни в коем случае выходить наружу. Оставаться в безопасном доме, вдали от окон, и тихо ждать, пока буря полностью не пройдёт, — правильное действие." },
  { id:59, topic:"Песчаные бури", emoji:"🏜️",
    question:"Когда случается песчаная буря (песок и пыль, поднятые сильным ветром), что нужно сделать, чтобы защитить глаза и лёгкие?",
    choices:["Широко открыть глаза и рот и принимать ветер","Плотно прикрыть лицо, рот и нос платком или тканью и спрятаться внутри прочного здания","Выйти наружу и наперегонки бегать с друзьями","Смотреть на небо, чтобы увидеть, как далеко летит песок"],
    answerIndex:1,
    explanation:"Песчаная буря, что случается у пустыни или в сухом краю, — это большая буря, поднимающая сильным ветром сотни миллионов мелких песчинок и грязной пыли. Если вдохнуть этот песок и пыль как есть, песок скапливается в глубине лёгких, и ты сильно кашляешь — серьёзная болезнь, при которой не можешь дышать. Кроме того, глаза могут пораниться песком, и ты не видишь. Когда песчаная буря приближается, сразу эвакуируйся внутрь прочного здания и закрой окна и двери без щелей. Затем сложи много раз платок или тканевую одежду, что у тебя есть, и плотно прикрой всё лицо, особенно рот и нос, сделав маску, не пускающую песок. Пока буря не пройдёт, защищай себя, тихо вдыхая только воздух, проходящий сквозь ткань." },
  { id:60, topic:"Наводнения", emoji:"🌊",
    question:"Во время наводнения, когда грязная вода врывается в дом, почему находиться в подвале (комнате ниже уровня земли) абсолютно нельзя?",
    choices:["Потому что в подвале прохладнее и удобнее, чем в других комнатах","Потому что грязная вода с дороги наверху врывается разом, как водопад, выход перекрывается, и ты тонешь в мгновение","Потому что подвал становится тёмным, когда отключается свет","Потому что в подвале иногда живут маленькие крысы"],
    answerIndex:1,
    explanation:"Подвал или полуподвальная комната ниже уровня земли превращается в самое смертельное, самое опасное место в мире, когда случается наводнение. Грязная вода, что вышла из берегов на дороге наверху, врывается разом через лестницу и окна подвала с огромной силой и весом водопада. Сила воды, текущей вниз по лестнице, чудовищна, и даже сила взрослого не может ей противиться, чтобы подняться. Более того, вес воды давит на дверь подвала снаружи, и изнутри её становится абсолютно невозможно открыть. Комната в мгновение наполняется водой, путь к спасению полностью теряется, и ты тонешь. Когда дождь усилится, абсолютное железное правило: никогда не подходи к подвалу, поднимись на верхний этаж прямо сейчас." }
];
